class DeviceController:
    """Controls device outputs - LEDs, relays, PWM, etc."""

    def __init__(self):
        self._led_state = False
        self._relay_state = False
        self._pwm_value = 0

        # Initialize GPIO pins
        try:
            self._led_pin = machine.Pin(2, machine.Pin.OUT)  # Built-in LED
            self._relay_pin = machine.Pin(26, machine.Pin.OUT)
            self._pwm_pin = machine.PWM(machine.Pin(25), freq=1000, duty=0)
        except Exception as e:
            print("GPIO init warning:", e)
            self._led_pin = None
            self._relay_pin = None
            self._pwm_pin = None

        # Additional controllable pins
        self._gpio_pins = {}

    def set_led(self, state):
        """Control LED on/off"""
        self._led_state = bool(state)
        if self._led_pin:
            self._led_pin.value(1 if self._led_state else 0)
        print("LED:", "ON" if self._led_state else "OFF")
        return self._led_state

    def get_led_state(self):
        return self._led_state

    def set_relay(self, state):
        """Control relay on/off"""
        self._relay_state = bool(state)
        if self._relay_pin:
            self._relay_pin.value(1 if self._relay_state else 0)
        print("Relay:", "ON" if self._relay_state else "OFF")
        return self._relay_state

    def get_relay_state(self):
        return self._relay_state

    def set_pwm(self, value):
        """Set PWM duty cycle (0-1023)"""
        self._pwm_value = max(0, min(1023, int(value)))
        if self._pwm_pin:
            self._pwm_pin.duty(self._pwm_value)
        print("PWM:", self._pwm_value)
        return self._pwm_value

    def get_pwm_value(self):
        return self._pwm_value

    def process_command(self, command_str):
        """Process JSON command and return response"""
        try:
            cmd = json.loads(command_str)
            action = cmd.get("action", "")
            params = cmd.get("params", {})

            if action == "led":
                state = self.set_led(params.get("state", False))
                return json.dumps({"status": "ok", "led": state})

            elif action == "relay":
                state = self.set_relay(params.get("state", False))
                return json.dumps({"status": "ok", "relay": state})

            elif action == "pwm":
                value = self.set_pwm(params.get("value", 0))
                return json.dumps({"status": "ok", "pwm": value})

            elif action == "status":
                return json.dumps({
                    "status": "ok",
                    "led": self._led_state,
                    "relay": self._relay_state,
                    "pwm": self._pwm_value
                })

            elif action == "reboot":
                return json.dumps({"status": "ok", "msg": "rebooting"})

            elif action == "ping":
                return json.dumps({"status": "ok", "msg": "pong"})

            elif action == "gpio":
                pin_num = params.get("pin")
                pin_val = params.get("value", 0)
                if pin_num is not None:
                    if pin_num not in self._gpio_pins:
                        self._gpio_pins[pin_num] = machine.Pin(pin_num, machine.Pin.OUT)
                    self._gpio_pins[pin_num].value(pin_val)
                    return json.dumps({"status": "ok", "pin": pin_num, "value": pin_val})
                return json.dumps({"status": "error", "msg": "missing pin"})

            else:
                return json.dumps({"status": "error", "msg": "unknown action"})

        except ValueError:
            return json.dumps({"status": "error", "msg": "invalid JSON"})
        except Exception as e:
            return json.dumps({"status": "error", "msg": str(e)})


