class BLEIoTDevice:
    """Main BLE IoT Device class - GATT server with sensor, control, and config services"""

    def __init__(self, device_name="ESP32-IoT"):
        self._ble = bluetooth.BLE()
        self._ble.active(True)
        self._ble.irq(self._irq_handler)

        self._device_name = device_name
        self._connections = set()
        self._connected_devices = {}

        # Initialize managers
        self._sensors = SensorManager()
        self._controller = DeviceController()
        self._config = DeviceConfig()

        # Use saved device name if available
        if self._config._device_name:
            self._device_name = self._config._device_name

        # Notification flags
        self._notify_enabled = {}
        self._notification_timer = None

        # Command response buffer
        self._command_response = ""

        # Register GATT services
        self._register_services()

        # Start advertising
        self._advertise()

        print("BLE IoT Device '{}' initialized".format(self._device_name))
        print("Waiting for connections...")

    def _register_services(self):
        """Register all GATT services and characteristics"""

        # Device Info Service
        _device_info_service = (
            _DEVICE_INFO_SERVICE_UUID,
            (
                (_MANUFACTURER_NAME_UUID, _FLAG_READ),
                (_MODEL_NUMBER_UUID, _FLAG_READ),
                (_FIRMWARE_VERSION_UUID, _FLAG_READ),
            ),
        )

        # Sensor Service
        _sensor_service = (
            _SENSOR_SERVICE_UUID,
            (
                (_TEMPERATURE_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                (_HUMIDITY_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                (_LIGHT_LEVEL_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                (_BATTERY_LEVEL_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                (_SENSOR_DATA_JSON_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
            ),
        )

        # Control Service
        _control_service = (
            _CONTROL_SERVICE_UUID,
            (
                (_LED_CONTROL_CHAR_UUID, _FLAG_READ | _FLAG_WRITE),
                (_RELAY_CONTROL_CHAR_UUID, _FLAG_READ | _FLAG_WRITE),
                (_PWM_CONTROL_CHAR_UUID, _FLAG_READ | _FLAG_WRITE),
                (_COMMAND_CHAR_UUID, _FLAG_WRITE | _FLAG_WRITE_NO_RESPONSE),
                (_COMMAND_RESPONSE_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
            ),
        )

        # Config Service
        _config_service = (
            _CONFIG_SERVICE_UUID,
            (
                (_DEVICE_NAME_CHAR_UUID, _FLAG_READ | _FLAG_WRITE),
                (_WIFI_SSID_CHAR_UUID, _FLAG_READ | _FLAG_WRITE),
                (_WIFI_PASS_CHAR_UUID, _FLAG_WRITE),
                (_CONFIG_JSON_CHAR_UUID, _FLAG_READ | _FLAG_WRITE),
            ),
        )

        # Register all services at once
        (
            (self._h_manufacturer, self._h_model, self._h_firmware),
            (self._h_temp, self._h_humidity, self._h_light, self._h_battery, self._h_sensor_json),
            (self._h_led, self._h_relay, self._h_pwm, self._h_command, self._h_command_resp),
            (self._h_dev_name, self._h_wifi_ssid, self._h_wifi_pass, self._h_config_json),
        ) = self._ble.gatts_register_services((
            _device_info_service,
            _sensor_service,
            _control_service,
            _config_service,
        ))

        # Set initial values for Device Info
        self._ble.gatts_write(self._h_manufacturer, b"ESP32 IoT Lab")
        self._ble.gatts_write(self._h_model, b"IoT-Device-v1")
        self._ble.gatts_write(self._h_firmware, b"1.0.0")

        # Set initial values for readable characteristics
        self._update_sensor_characteristics()
        self._ble.gatts_write(self._h_led, struct.pack("B", 0))
        self._ble.gatts_write(self._h_relay, struct.pack("B", 0))
        self._ble.gatts_write(self._h_pwm, struct.pack("<H", 0))
        self._ble.gatts_write(self._h_command_resp, b"")
        self._ble.gatts_write(self._h_dev_name, self._device_name.encode())
        self._ble.gatts_write(self._h_wifi_ssid, self._config._wifi_ssid.encode())
        self._ble.gatts_write(self._h_config_json, self._config.get_config_json().encode())

        # Set larger buffer for JSON characteristics
        try:
            self._ble.gatts_set_buffer(self._h_sensor_json, 512)
            self._ble.gatts_set_buffer(self._h_command, 512)
            self._ble.gatts_set_buffer(self._h_command_resp, 512)
            self._ble.gatts_set_buffer(self._h_config_json, 512)
        except:
            pass  # Some versions may not support this

    def _irq_handler(self, event, data):
        """Handle BLE IRQ events"""

        if event == _IRQ_CENTRAL_CONNECT:
            conn_handle, addr_type, addr = data
            addr_str = ":".join(["{:02x}".format(b) for b in addr])
            print("Connected: handle={}, addr={}".format(conn_handle, addr_str))
            self._connections.add(conn_handle)
            self._connected_devices[conn_handle] = {
                "addr": addr_str,
                "connected_at": time.time()
            }
            # Continue advertising to allow multiple connections
            self._advertise()

        elif event == _IRQ_CENTRAL_DISCONNECT:
            conn_handle, addr_type, addr = data
            print("Disconnected: handle={}".format(conn_handle))
            self._connections.discard(conn_handle)
            self._connected_devices.pop(conn_handle, None)
            self._notify_enabled.pop(conn_handle, None)
            # Restart advertising
            self._advertise()

        elif event == _IRQ_GATTS_WRITE:
            conn_handle, attr_handle = data
            value = self._ble.gatts_read(attr_handle)
            self._handle_write(conn_handle, attr_handle, value)

        elif event == _IRQ_GATTS_READ_REQUEST:
            conn_handle, attr_handle = data
            self._handle_read_request(conn_handle, attr_handle)

        elif event == _IRQ_MTU_EXCHANGED:
            conn_handle, mtu = data
            print("MTU exchanged: handle={}, mtu={}".format(conn_handle, mtu))

    def _handle_write(self, conn_handle, attr_handle, value):
        """Handle write requests to characteristics"""

        if attr_handle == self._h_led:
            state = struct.unpack("B", value)[0] if value else 0
            self._controller.set_led(state)
            self._ble.gatts_write(self._h_led, struct.pack("B", 1 if self._controller.get_led_state() else 0))
            print("BLE Write - LED:", state)

        elif attr_handle == self._h_relay:
            state = struct.unpack("B", value)[0] if value else 0
            self._controller.set_relay(state)
            self._ble.gatts_write(self._h_relay, struct.pack("B", 1 if self._controller.get_relay_state() else 0))
            print("BLE Write - Relay:", state)

        elif attr_handle == self._h_pwm:
            if len(value) >= 2:
                pwm_val = struct.unpack("<H", value[:2])[0]
            else:
                pwm_val = struct.unpack("B", value)[0]
            self._controller.set_pwm(pwm_val)
            self._ble.gatts_write(self._h_pwm, struct.pack("<H", self._controller.get_pwm_value()))
            print("BLE Write - PWM:", pwm_val)

        elif attr_handle == self._h_command:
            command_str = value.decode("utf-8") if value else ""
            print("BLE Command:", command_str)
            response = self._controller.process_command(command_str)
            self._command_response = response
            resp_bytes = response.encode("utf-8")
            self._ble.gatts_write(self._h_command_resp, resp_bytes)
            # Notify connected clients of the response
            self._notify_characteristic(self._h_command_resp, resp_bytes)

            # Handle special commands
            try:
                cmd = json.loads(command_str)
                if cmd.get("action") == "reboot":
                    time.sleep(1)
                    machine.reset()
            except:
                pass

        elif attr_handle == self._h_dev_name:
            self._config.set_device_name(value)
            self._device_name = value.decode() if isinstance(value, bytes) else value
            self._ble.gatts_write(self._h_dev_name, self._device_name.encode())
            print("Device name set to:", self._device_name)

        elif attr_handle == self._h_wifi_ssid:
            self._config.set_wifi_ssid(value)
            self._ble.gatts_write(self._h_wifi_ssid, value)
            print("WiFi SSID set")

        elif attr_handle == self._h_wifi_pass:
            self._config.set_wifi_pass(value)
            print("WiFi password set")

        elif attr_handle == self._h_config_json:
            config_str = value.decode("utf-8") if isinstance(value, bytes) else value
            if self._config.set_config_json(config_str):
                print("Config updated via JSON")
            else:
                print("Config update failed - invalid JSON")
            self._ble.gatts_write(self._h_config_json, self._config.get_config_json().encode())

    def _handle_read_request(self, conn_handle, attr_handle):
        """Handle read requests - update values before they're read"""
        if attr_handle in (self._h_temp, self._h_humidity, self._h_light,
                           self._h_battery, self._h_sensor_json):
            self._update_sensor_characteristics()

    def _update_sensor_characteristics(self):
        """Update all sensor characteristic values"""
        temp = self._sensors.read_temperature()
        humidity = self._sensors.read_humidity()
        light = self._sensors.read_light_level()
        battery = self._sensors.read_battery_level()

        # Pack as IEEE 754 floats and integers
        self._ble.gatts_write(self._h_temp, struct.pack("<f", temp))
        self._ble.gatts_write(self._h_humidity, struct.pack("<f", humidity))
        self._ble.gatts_write(self._h_light, struct.pack("<H", light))
        self._ble.gatts_write(self._h_battery, struct.pack("B", battery))

        # JSON with all sensor data
        sensor_data = self._sensors.get_all_sensor_data()
        self._ble.gatts_write(self._h_sensor_json, json.dumps(sensor_data).encode())

    def _notify_characteristic(self, handle, data):
        """Send notification to all connected clients"""
        for conn_handle in list(self._connections):
            try:
                self._ble.gatts_notify(conn_handle, handle, data)
            except Exception as e:
                print("Notify error for handle {}: {}".format(conn_handle, e))
                self._connections.discard(conn_handle)

    def send_sensor_notifications(self):
        """Send sensor data notifications to all connected clients"""
        if not self._connections:
            return

        self._update_sensor_characteristics()

        temp = self._sensors.read_temperature()
        humidity = self._sensors.read_humidity()
        light = self._sensors.read_light_level()
        battery = self._sensors.read_battery_level()

        self._notify_characteristic(self._h_temp, struct.pack("<f", temp))
        self._notify_characteristic(self._h_humidity, struct.pack("<f", humidity))
        self._notify_characteristic(self._h_light, struct.pack("<H", light))
        self._notify_characteristic(self._h_battery, struct.pack("B", battery))

        sensor_json = json.dumps(self._sensors.get_all_sensor_data())
        self._notify_characteristic(self._h_sensor_json, sensor_json.encode())

    def _advertise(self):
        """Start BLE advertising"""
        name_bytes = self._device_name.encode("utf-8")[:20]

        # Build advertising payload
        adv_data = bytearray()

        # Flags: General Discoverable + BR/EDR Not Supported
        adv_data += struct.pack("BBB", 2, 0x01, 0x06)

        # Complete Local Name
        adv_data += struct.pack("BB", len(name_bytes) + 1, 0x09)
        adv_data += name_bytes

        # Scan response with service UUIDs
        resp_data = bytearray()

        # Include 16-bit service UUID (Device Information)
        resp_data += struct.pack("BBH", 3, 0x03, 0x180A)

        # TX Power Level
        resp_data += struct.pack("BBb", 2, 0x0A, 0)

        try:
            self._ble.gap_advertise(
                _ADV_INTERVAL_US,
                adv_data=bytes(adv_data),
                resp_data=bytes(resp_data),
                connectable=True
            )
            print("Advertising as '{}'...".format(self._device_name))
        except Exception as e:
            print("Advertise error:", e)
            # Try simpler advertising
            try:
                self._ble.gap_advertise(_ADV_INTERVAL_US, adv_data=bytes(adv_data))
            except Exception as e2:
                print("Simple advertise error:", e2)

    def is_connected(self):
        """Check if any client is connected"""
        return len(self._connections) > 0

    def connection_count(self):
        """Return number of active connections"""
        return len(self._connections)

    def get_connection_info(self):
        """Return info about connected devices"""
        return dict(self._connected_devices)

    def stop(self):
        """Stop BLE and clean up"""
        print("Stopping BLE IoT Device...")
        try:
            self._ble.gap_advertise(None)
        except:
            pass
        self._ble.active(False)
        print("BLE stopped")


